open! Core
open Hardcaml
open Hardcaml_framebuffer_expander
open Hardcaml_test_harness
open! Bits

module FBC = struct
  let input_width = 64
  let input_height = 32
  let output_width = 64
  let output_height = 32
  let input_pixel_mode = Pixel_mode.RGB_8bit_32bit_aligned
end

module Memory_controller = Test_memory_controller

module Machine = struct
  open Signal
  open Memory_controller.Memory_bus

  module Framebuffer_expander =
    Framebuffer_expander.Make (FBC) (Memory_controller.Memory_bus)

  module I = struct
    type 'a t =
      { clock : 'a
      ; clear : 'a
      ; start_frame : 'a
      ; next_pixel : 'a
      }
    [@@deriving hardcaml]
  end

  module O = struct
    type 'a t =
      { r : 'a [@bits 8]
      ; g : 'a [@bits 8]
      ; b : 'a [@bits 8]
      }
    [@@deriving hardcaml]
  end

  let create (scope : Scope.t) { I.clock; clear; start_frame; next_pixel } =
    let request_ack = Read_bus.Dest.Of_signal.wires () in
    let response = Read_response.With_valid.Of_signal.wires () in
    let frame =
      Framebuffer_expander.hierarchical
        scope
        { Framebuffer_expander.I.clock = { clock; clear }
        ; start = start_frame
        ; start_address = zero 32
        ; next = next_pixel
        ; memory_request = request_ack
        ; memory_response = response
        }
    in
    let controller =
      Memory_controller.hierarchical
        ~build_mode:Simulation
        ~priority_mode:Priority_order
        ~read_latency:1
        scope
        { Memory_controller.I.clock = { clock; clear }
        ; read_to_controller = [ frame.memory_request ]
        ; write_to_controller = [ Write_bus.Source.Of_signal.zero () ]
        }
    in
    Read_bus.Dest.Of_signal.(request_ack <-- List.hd_exn controller.read_to_controller);
    Read_response.With_valid.Of_signal.(response <-- List.hd_exn controller.read_response);
    { O.r = frame.pixel.r; g = frame.pixel.g; b = frame.pixel.b }
  ;;
end

module Harness = Cyclesim_harness.Make (Machine.I) (Machine.O)

let program_ram sim bits =
  let ram = Cyclesim.lookup_mem_by_name sim "main_memory_bram" |> Option.value_exn in
  List.iteri ~f:(fun i m -> Cyclesim.Memory.of_bits ~address:i ram m) bits
;;

let debug = false

let dog_image_64x32 =
  let width = 64 in
  let height = 32 in
  (* Define colors as (R, G, B) tuples *)
  let sky = 135, 206, 235 in
  let grass = 34, 139, 34 in
  let fur = 139, 69, 19 in
  let ear = 93, 46, 12 in
  let eye = 0, 0, 0 in
  let nose = 26, 26, 26 in
  List.init height ~f:(fun y ->
    List.init width ~f:(fun x ->
      if y > 26
      then grass
      else if y > 18 && y < 22 && x > 15 && x < 19
      then fur
      else if y > 18 && y < 28 && x >= 18 && x <= 45
      then fur
      else if
        y >= 28
        && ((x >= 20 && x <= 22)
            || (x >= 26 && x <= 28)
            || (x >= 35 && x <= 37)
            || (x >= 41 && x <= 43))
      then fur
      else if y > 12 && y <= 18 && x > 38 && x < 52
      then fur
      else if y > 14 && y < 22 && (x = 38 || x = 52)
      then ear
      else if y = 15 && (x = 42 || x = 48)
      then eye
      else if y = 17 && x = 51
      then nose
      else sky))
;;

let test ~framebuffers =
  Harness.run
    ~trace:`All_named (* Needed so the BRAM doesn't get optimized away. *)
    ~create:Machine.create
    ~waves_config:(Waves_config.to_home_subdirectory_when debug)
    (fun ~inputs ~outputs sim ->
       inputs.clear := vdd;
       Cyclesim.cycle sim;
       Cyclesim.cycle sim;
       Cyclesim.cycle sim;
       inputs.clear := gnd;
       Array.iteri
         ~f:(fun idx framebuffer ->
           print_s [%message "testing" ~length:(List.length framebuffer : int)];
           program_ram sim framebuffer;
           let wait_some_cycles_and_sample () =
             Sequence.range 0 10 |> Sequence.iter ~f:(fun _ -> Cyclesim.cycle sim);
             let r, g, b =
               ( Bits.to_int_trunc !(outputs.r)
               , Bits.to_int_trunc !(outputs.g)
               , Bits.to_int_trunc !(outputs.b) )
             in
             inputs.next_pixel := vdd;
             Cyclesim.cycle sim;
             inputs.next_pixel := gnd;
             r, g, b
           in
           inputs.start_frame := vdd;
           Cyclesim.cycle sim;
           inputs.start_frame := gnd;
           let frame_buffer =
             Array.init
               ~f:(fun _ -> wait_some_cycles_and_sample ())
               (FBC.output_width * FBC.output_height)
           in
           printf "Framebuffer %i\n" idx;
           Sequence.range 0 FBC.output_height
           |> Sequence.iter ~f:(fun y ->
             Sequence.range 0 FBC.output_width
             |> Sequence.iter ~f:(fun x ->
               let r, g, b = Array.get frame_buffer ((y * FBC.output_width) + x) in
               let draw = r <> 0 || g <> 0 || b <> 0 in
               let p c r g b = printf "\x1b[38;2;%d;%d;%dm%c\x1b[0m" r g b c in
               if draw then p '*' r g b else p '-' r g b);
             printf "\n"))
         framebuffers)
;;

let%expect_test "details" =
  print_s
    [%message
      (Machine.Framebuffer_expander.scaling_factor_y : int)
        (Machine.Framebuffer_expander.scaling_factor_x : int)
        (Machine.Framebuffer_expander.margin_x_start : int)
        (Machine.Framebuffer_expander.margin_x_end : int)
        (Machine.Framebuffer_expander.margin_y_start : int)
        (Machine.Framebuffer_expander.margin_y_end : int)];
  [%expect
    {|
    ((Machine.Framebuffer_expander.scaling_factor_y 1)
     (Machine.Framebuffer_expander.scaling_factor_x 1)
     (Machine.Framebuffer_expander.margin_x_start 0)
     (Machine.Framebuffer_expander.margin_x_end 0)
     (Machine.Framebuffer_expander.margin_y_start 0)
     (Machine.Framebuffer_expander.margin_y_end 0))
    |}]
;;

let%expect_test "test" =
  let pixel r g b =
    concat_lsb
      [ of_int_trunc ~width:8 r
      ; of_int_trunc ~width:8 g
      ; of_int_trunc ~width:8 b
      ; zero 8
      ]
  in
  let black_pixel = pixel 0 0 0 in
  let white_pixel = pixel 255 255 255 in
  let empty_half_row = List.init ~f:(fun _ -> black_pixel) 32 |> Bits.concat_lsb in
  let full_half_row = List.init ~f:(fun _ -> white_pixel) 32 |> Bits.concat_lsb in
  let a_row = Bits.concat_lsb [ empty_half_row; full_half_row ] in
  let b_row = Bits.concat_lsb [ full_half_row; empty_half_row ] in
  let framebuffer_0 =
    List.init ~f:(fun i -> if i % 2 = 1 then a_row else b_row) 32
    |> Bits.concat_lsb
    |> Bits.split_lsb ~part_width:8
  in
  let by = Bits.of_int_trunc ~width:8 in
  let framebuffer_1 =
    List.concat dog_image_64x32
    |> List.map ~f:(fun (r, g, b) -> concat_lsb [ by r; by g; by b; by 0 ])
    |> Bits.concat_lsb
    |> Bits.split_lsb ~part_width:8
  in
  test ~framebuffers:[| framebuffer_0; framebuffer_1 |];
